#include<bits/stdc++.h>
using namespace std;
typedef long long ll;

int main() {
	std::ios::sync_with_stdio(false);
	std::cin.tie(nullptr);

	int n;
	cin >> n;
	string str;
	unordered_map<string,vector<string>> map;
	while (n--) {
		cin >> str;
        int counts[50] = {0};
        for (char c : str) {
            counts[c - '0']++;
        }
        string key = "";
        for (int i = 0; i < 50; i++) {
            if (counts[i] > 0) {
                key.push_back(i + 'a');
                key.append(to_string(counts[i])); // 改为添加数字字符串
            }
        }
        map[key].push_back(str);
    }
    cout << map.size(); 
	return 0;
}
